mapper.select:
select c.id, m.major_name, c.class_name, t.name as head_teacher_name, c.status, c.create_time from class c left join major m on c.major_id = m.id left join teacher t on c.head_teacher_id = t.id
and c.major_id = #{majorId}
and c.class_name like concat('%', #{className}, '%')
and c.status = #{status}
order by c.create_time desc
